export interface AdItem {
  id: string;
  imageSrc: string;
  price: string;
  span: 1 | 2 | 3 | 4; // 1 = Quarter, 2 = Half, 3 = Three Quarters, 4 = Full Row
  offsetX: number;
  offsetY: number;
  scale: number; // Percentage (e.g., 100 = 1x)
  name?: string;
}

export interface AdConfig {
  backgroundColor: string;
  backgroundSrc: string | null;
  headerLogoSrc: string | null;
  cardBackgroundSrc: string | null;
  footerText: string;
  footerColor: string;
  priceTagColor: string;
  gridColumns: 3 | 4;
  aspectRatio: 'auto' | '1:1' | '3:4' | '4:3';
}

export const SPAN_OPTIONS = [
  { value: 1, label: '1x' },
  { value: 2, label: '2x' },
  { value: 3, label: '3x' },
