] as const;

import React, { useState, useCallback, useRef } from 'react';
import { AdItem, AdConfig } from './types';
import EditorSidebar from './components/EditorSidebar';
import AdPreview from './components/AdPreview';
import { Download, Layout, Menu } from 'lucide-react';
import { toJpeg } from 'html-to-image';

export default function App() {
  // --- State ---
  const [items, setItems] = useState<AdItem[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [config, setConfig] = useState<AdConfig>({
    backgroundColor: '#D35400',
    backgroundSrc: null,
    headerLogoSrc: null,
    cardBackgroundSrc: null,
    footerText: 'FB.COM/RXDGREGALOS',
    footerColor: '#E91E63',
    priceTagColor: '#D35400', // Default brand orange
    gridColumns: 4,
    aspectRatio: 'auto',
  });
  const [isExporting, setIsExporting] = useState(false);
  const previewRef = useRef<HTMLDivElement>(null);

  // --- Handlers ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newItems: AdItem[] = Array.from(e.target.files).map((file: File) => {
        const nameWithoutExt = file.name.substring(0, file.name.lastIndexOf('.')) || file.name;

        // Price Extraction Logic
        // Looks for " S <number>" at the end of the filename (case insensitive)
        // Example: "Guff espectral S 18" -> Matches "18"
        // Example: "Skin Name S 25.50" -> Matches "25.50"
        let extractedPrice = 'S/19.99'; // Default fallback (No space)
        const priceMatch = nameWithoutExt.match(/\sS\s*(\d+(\.\d{1,2})?)$/i);

        if (priceMatch && priceMatch[1]) {
            extractedPrice = `S/${priceMatch[1]}`; // No space
        }

        return {
          id: crypto.randomUUID(),
          imageSrc: URL.createObjectURL(file),
          price: extractedPrice,
          span: 1,
          offsetX: 0,
          offsetY: 0,
          scale: 100, // Default 100% scale
          name: nameWithoutExt,
        };
      });
      setItems((prev) => [...prev, ...newItems]);
    }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const url = URL.createObjectURL(e.target.files[0]);
      setConfig((prev) => ({ ...prev, headerLogoSrc: url }));
    }
  };

  const handleBackgroundUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const url = URL.createObjectURL(e.target.files[0]);
      setConfig((prev) => ({ ...prev, backgroundSrc: url }));
    }
  };

  const handleCardBackgroundUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const url = URL.createObjectURL(e.target.files[0]);
      setConfig((prev) => ({ ...prev, cardBackgroundSrc: url }));
    }
  };

  const updateItem = (id: string, updates: Partial<AdItem>) => {
    setItems((prev) => prev.map((item) => (item.id === id ? { ...item, ...updates } : item)));
  };

  const deleteItem = (id: string) => {
    setItems((prev) => prev.filter((item) => item.id !== id));
    if (selectedId === id) setSelectedId(null);
  };

  const moveItem = (id: string, direction: 'forward' | 'backward') => {
    const index = items.findIndex((i) => i.id === id);
    if (index === -1) return;

    const newItems = [...items];
    if (direction === 'backward' && index > 0) {
      [newItems[index - 1], newItems[index]] = [newItems[index], newItems[index - 1]];
    } else if (direction === 'forward' && index < newItems.length - 1) {
      [newItems[index + 1], newItems[index]] = [newItems[index], newItems[index + 1]];
    }
    setItems(newItems);
  };

  const handleReorder = (dragIndex: number, hoverIndex: number) => {
    const newItems = [...items];
    const [draggedItem] = newItems.splice(dragIndex, 1);
    newItems.splice(hoverIndex, 0, draggedItem);
    setItems(newItems);
  };

  const handleExport = useCallback(async () => {
    if (previewRef.current === null) return;
    setIsExporting(true);
    setSelectedId(null); // Deselect before export

    try {
      // Small delay to ensure any render updates are done
      await new Promise(resolve => setTimeout(resolve, 100));

      const dataUrl = await toJpeg(previewRef.current, { 
        quality: 0.95,
        backgroundColor: config.backgroundColor,
      });

      const link = document.createElement('a');
      link.download = `rxdg-ad-${Date.now()}.jpg`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Failed to export image', err);
      alert('Failed to generate image. Please try again.');
    } finally {
      setIsExporting(false);
    }
  }, [config.backgroundColor]);

  const selectedItem = items.find((i) => i.id === selectedId);

  return (
    <div className="flex h-screen w-full bg-neutral-900 text-gray-100 font-sans overflow-hidden">

      {/* Left Panel: Editor Sidebar */}
      <div className="w-80 flex-shrink-0 border-r border-neutral-800 bg-neutral-900 z-20 flex flex-col h-full shadow-xl">
        <div className="p-5 border-b border-neutral-800 flex items-center gap-3">
          <div className="p-2 bg-brand-orange rounded-lg">
            <Layout className="w-6 h-6 text-white" />
          </div>
          <h1 className="font-bold text-xl tracking-tight">RXDG Builder</h1>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar">
           <EditorSidebar 
             config={config}
             setConfig={setConfig}
             selectedItem={selectedItem}
             updateItem={updateItem}
             deleteItem={deleteItem}
             moveItem={moveItem}
             onDeselect={() => setSelectedId(null)}
             onUploadImages={handleFileUpload}
             onUploadLogo={handleLogoUpload}
             onUploadBackground={handleBackgroundUpload}
             onUploadCardBackground={handleCardBackgroundUpload}
           />
        </div>

        <div className="p-4 border-t border-neutral-800 bg-neutral-900">
           <button 
             onClick={handleExport}
             disabled={isExporting || items.length === 0}
             className={`w-full py-3 px-4 rounded-lg font-bold flex items-center justify-center gap-2 transition-all transform active:scale-95
               ${isExporting || items.length === 0 
                 ? 'bg-neutral-700 text-neutral-500 cursor-not-allowed' 
                 : 'bg-green-600 hover:bg-green-500 text-white shadow-lg shadow-green-900/20'}`}
           >
             {isExporting ? 'Rendering...' : (
               <>
                 <Download size={20} />
                 Export High-Res JPG
               </>
             )}
           </button>
        </div>
      </div>

      {/* Right Panel: Canvas Preview */}
      <div className="flex-1 bg-neutral-950 relative overflow-hidden flex flex-col">
        {/* Toolbar / Status Bar */}
        <div className="h-14 border-b border-neutral-800 bg-neutral-900/50 flex items-center justify-between px-6 backdrop-blur-md z-10">
          <span className="text-neutral-400 text-sm flex items-center gap-2">
            <Menu size={16} />
            {items.length} Items on Canvas
          </span>
          <div className="flex items-center gap-4 text-xs font-mono text-neutral-500">
             <span>AUTOSAVE: ON</span>
             <span>ZOOM: FIT</span>
          </div>
        </div>

        {/* Scrollable Canvas Area */}
        <div 
          className="flex-1 overflow-auto p-8 flex justify-center items-start custom-scrollbar bg-[radial-gradient(#222_1px,transparent_1px)] [background-size:16px_16px]"
          onClick={() => setSelectedId(null)} // Click outside to deselect
        >
          <div 
            className={`relative transition-all duration-300 ease-in-out origin-top shadow-2xl ${isExporting ? 'scale-100' : 'scale-[0.85] lg:scale-100'}`}
            onClick={(e) => e.stopPropagation()} // Prevent deselecting when clicking the canvas itself
          >
            <AdPreview 
              ref={previewRef}
              items={items}
              config={config}
              selectedId={selectedId}
              onSelectItem={setSelectedId}
              onReorder={handleReorder}
            />
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { forwardRef, useState } from 'react';
import { AdItem, AdConfig } from '../types';

interface AdPreviewProps {
  items: AdItem[];
  config: AdConfig;
  selectedId: string | null;
  onSelectItem: (id: string) => void;
  onReorder: (dragIndex: number, hoverIndex: number) => void;
}

const AdPreview = forwardRef<HTMLDivElement, AdPreviewProps>(({ items, config, selectedId, onSelectItem, onReorder }, ref) => {
  const [draggingIndex, setDraggingIndex] = useState<number | null>(null);

  const handleDragStart = (e: React.DragEvent, index: number) => {
    setDraggingIndex(index);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    if (draggingIndex !== null && draggingIndex !== index) {
      onReorder(draggingIndex, index);
    }
    setDraggingIndex(null);
  };

  return (
    <div 
      ref={ref}
      className="w-[1200px] min-h-[800px] flex flex-col relative bg-cover bg-center"
      style={{ 
        backgroundColor: config.backgroundColor,
        backgroundImage: config.backgroundSrc ? `url(${config.backgroundSrc})` : 'none'
      }}
    >
      {/* --- HEADER --- */}
      <div className="w-full p-8 flex items-center justify-center relative z-10 min-h-[150px]">
        {config.headerLogoSrc ? (
            <img 
              src={config.headerLogoSrc} 
              alt="Logo" 
              className="h-full w-auto max-h-[150px] max-w-[33%] object-contain drop-shadow-2xl filter"
            />
        ) : (
            <div className="border-2 border-dashed border-white/30 rounded px-6 py-4 text-white/50 text-xl font-bold uppercase">
                Upload Logo Here
            </div>
        )}
      </div>

      {/* --- GRID --- */}
      <div className="flex-1 p-6 z-10">
        <div className={`grid gap-4 auto-rows-min ${config.gridColumns === 3 ? 'grid-cols-3' : 'grid-cols-4'}`}>
          {items.map((item, index) => {
            // Determine sizing classes
            const colSpanClass = {
              1: 'col-span-1',
              2: 'col-span-2',
              3: 'col-span-3',
              4: 'col-span-4'
            }[item.span];

            // Aspect Ratio classes
            let aspectRatioClass = '';
            let heightClass = '';

            if (config.aspectRatio === 'auto') {
                heightClass = item.span === 4 ? 'h-[500px]' : 'h-[380px]';
            } else {
                heightClass = 'h-auto';
                aspectRatioClass = {
                    '1:1': 'aspect-square',
                    '3:4': 'aspect-[3/4]',
                    '4:3': 'aspect-[4/3]'
                }[config.aspectRatio] || '';
            }

            const isSelected = selectedId === item.id;
            const isDragging = draggingIndex === index;

            return (
              <div 
                key={item.id}
                draggable
                onDragStart={(e) => handleDragStart(e, index)}
                onDragOver={(e) => handleDragOver(e, index)}
                onDrop={(e) => handleDrop(e, index)}
                onClick={(e) => {
                  e.stopPropagation();
                  onSelectItem(item.id);
                }}
                className={`
                  ${colSpanClass} ${heightClass} ${aspectRatioClass}
                  relative group cursor-pointer overflow-hidden rounded-xl border-4 transition-all duration-200 shadow-2xl
                  ${isSelected ? 'border-yellow-400 ring-4 ring-yellow-400/30 z-20 scale-[1.02]' : 'border-transparent hover:border-white/30'}
                  ${isDragging ? 'opacity-40 border-dashed border-white' : ''}
                `}
              >
                {/* Background Image Container */}
                <div 
                  className="w-full h-full overflow-hidden relative"
                  style={{ 
                    backgroundImage: config.cardBackgroundSrc ? `url(${config.cardBackgroundSrc})` : 'none',
                    backgroundSize: 'cover',
                    backgroundPosition: 'center',
                  }}
                >
                    <img 
                    src={item.imageSrc} 
                    alt="Item" 
                    className="w-full h-full object-contain transition-transform duration-100 ease-out absolute inset-0"
                    style={{ 
                      transform: `translate(${item.offsetX || 0}px, ${item.offsetY}px) scale(${item.scale / 100})`
                    }}
                    />
                </div>

                {/* Dark Gradient Overlay */}
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent pointer-events-none" />

                {/* Price Tag & Info */}
                <div className="absolute bottom-4 left-4 right-4 flex flex-col gap-1 pointer-events-none">
                  <div 
                    className="self-start bg-neutral-900/90 backdrop-blur-md px-4 py-2 rounded transform -skew-x-12 border-l-4 shadow-lg"
                    style={{ borderColor: config.priceTagColor }}
                  >
                     <span className="block transform skew-x-12 text-5xl font-burbank text-white tracking-wider">
                       {item.price}
                     </span>
                  </div>
                </div>

                {/* Selection Indicator */}
                {isSelected && (
                  <div className="absolute top-2 right-2 bg-yellow-400 text-black px-2 py-1 text-xs font-bold rounded z-30">
                    EDITING
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {items.length === 0 && (
           <div className="h-64 border-4 border-dashed border-white/20 rounded-xl flex items-center justify-center text-white/30 font-bold text-2xl uppercase backdrop-blur-sm bg-black/20">
              Drop Items Here (Use Sidebar)
           </div>
        )}
      </div>

      {/* --- FOOTER --- */}
      <div 
        className="h-24 w-full mt-auto flex items-center justify-center text-white text-5xl font-burbank uppercase tracking-wider relative z-10"
        style={{ backgroundColor: config.footerColor }}
      >
         <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-20 mix-blend-overlay"></div>
         <span className="relative drop-shadow-md mt-2">{config.footerText}</span>
      </div>
    </div>
  );
});

