    if (draggingIndex !== null && draggingIndex !== index) {
      onReorder(draggingIndex, index);
    }
    setDraggingIndex(null);
  };

  // --- Lógica de Dimensiones Constantes Mejorada ---
  // Aumentamos el padding para un mejor centrado visual
  // px-16 equivale a 64px por lado. Total = 128px
  const horizontalPadding = 128; 
  const gapSize = 16;
  const availableWidth = 1200 - horizontalPadding;
  const columnWidth = (availableWidth - (gapSize * (config.gridColumns - 1))) / config.gridColumns;

  // Calculamos la altura base para una tarjeta de 1x según el ratio
  let baseHeight = 380; // Default "Auto"
  if (config.aspectRatio === '1:1') baseHeight = columnWidth;
  if (config.aspectRatio === '3:4') baseHeight = columnWidth * 1.333;
  if (config.aspectRatio === '4:3') baseHeight = columnWidth * 0.75;

  return (
    <div 
      ref={ref}
      className="w-[1200px] min-h-[800px] flex flex-col relative bg-cover bg-center"
      style={{ 
        backgroundColor: config.backgroundColor,
        backgroundImage: config.backgroundSrc ? `url(${config.backgroundSrc})` : 'none'
      }}
    >
      {/* --- HEADER --- */}
      <div className="w-full p-10 flex items-center justify-center relative z-10 min-h-[160px]">
        {config.headerLogoSrc ? (
            <img 
              src={config.headerLogoSrc} 
              alt="Logo" 
              className="h-full w-auto max-h-[150px] max-w-[40%] object-contain drop-shadow-2xl filter"
            />
        ) : (
            <div className="border-2 border-dashed border-white/30 rounded px-8 py-6 text-white/50 text-2xl font-bold uppercase tracking-widest">
                LOGO AQUÍ
            </div>
        )}
      </div>

      {/* --- GRID --- */}
      {/* Aplicamos px-16 para dar más margen lateral y py-8 para balance vertical */}
      <div className="flex-1 px-16 py-8 z-10">
        <div className={`grid gap-4 auto-rows-min ${config.gridColumns === 3 ? 'grid-cols-3' : 'grid-cols-4'}`}>
          {items.map((item, index) => {
            const colSpanClass = {
              1: 'col-span-1',
              2: 'col-span-2',
              3: 'col-span-3',
              4: 'col-span-4'
            }[item.span];

            const isFullRow = item.span === config.gridColumns;
            const finalHeight = isFullRow 
              ? (config.aspectRatio === 'auto' ? 500 : baseHeight * 1.25) 
              : baseHeight;

            const isSelected = selectedId === item.id;
            const isDragging = draggingIndex === index;

            return (
              <div 
                key={item.id}
                draggable
                onDragStart={(e) => handleDragStart(e, index)}
                onDragOver={(e) => handleDragOver(e, index)}
                onDrop={(e) => handleDrop(e, index)}
                onClick={(e) => {
                  e.stopPropagation();
                  onSelectItem(item.id);
                }}
                className={`
                  ${colSpanClass}
                  relative group cursor-pointer overflow-hidden rounded-xl border-4 transition-all duration-200 shadow-2xl
                  ${isSelected ? 'border-yellow-400 ring-4 ring-yellow-400/30 z-20 scale-[1.02]' : 'border-transparent hover:border-white/30'}
                  ${isDragging ? 'opacity-40 border-dashed border-white' : ''}
                `}
                style={{ height: `${finalHeight}px` }}
              >
                {/* Background Image Container */}
                <div 
                  className="w-full h-full overflow-hidden relative"
                  style={{ 
                    backgroundImage: config.cardBackgroundSrc ? `url(${config.cardBackgroundSrc})` : 'none',
                    backgroundSize: 'cover',
                    backgroundPosition: 'center',
                  }}
                >
                    <img 
                    src={item.imageSrc} 
                    alt="Item" 
                    className="w-full h-full object-contain transition-transform duration-100 ease-out absolute inset-0"
                    style={{ 
                      transform: `translate(${item.offsetX || 0}px, ${item.offsetY}px) scale(${item.scale / 100})`
                    }}
                    />
                </div>

                {/* Dark Gradient Overlay */}
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent pointer-events-none" />

                {/* Price Tag & Info */}
                <div className="absolute bottom-4 left-4 right-4 flex flex-col gap-1 pointer-events-none">
                  <div 
                    className="self-start bg-neutral-900/90 backdrop-blur-md px-4 py-2 rounded transform -skew-x-12 border-l-4 shadow-lg"
                    style={{ borderColor: config.priceTagColor }}
                  >
                     <span 
                        className="block transform skew-x-12 font-burbank text-white tracking-wider leading-none"
                        style={{ fontSize: `${config.priceSize}px` }}
                      >
                       {item.price}
                     </span>
                  </div>
                </div>

                {isSelected && (
                  <div className="absolute top-2 right-2 bg-yellow-400 text-black px-2 py-1 text-xs font-bold rounded z-30">
                    EDITANDO
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {items.length === 0 && (
           <div className="h-64 border-4 border-dashed border-white/20 rounded-xl flex items-center justify-center text-white/30 font-bold text-2xl uppercase backdrop-blur-sm bg-black/20">
              Arrastra o sube imágenes para comenzar
           </div>
        )}
      </div>

      {/* --- FOOTER --- */}
      <div 
        className="h-24 w-full mt-auto flex items-center justify-center text-white text-5xl font-burbank uppercase tracking-wider relative z-10"
        style={{ backgroundColor: config.footerColor }}
      >
         <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-20 mix-blend-overlay"></div>
         <span className="relative drop-shadow-md mt-2">{config.footerText}</span>
      </div>
    </div>
  );
});

AdPreview.displayName = 'AdPreview';
export default AdPreview;
